def memoize(f):
    cache = {}
    def inner(n):
        if n not in cache:
            cache[n] = f(n)
        return cache[n]
    return inner

@memoize
def fib(n):
    return n if n <= 1 else fib(n-1) + fib(n-2)

print(fib(6))
```
